const item = $input.first().json;
const form = item.form;

const bizName = form['Nama Bisnis'] || '';
const bizType = form['Jenis Bisnis'] || '';
const description = form['Deskripsi Layanan Utama'] || '';
const pricing = form['Daftar Produk/Paket + Harga'] || '';
const advantages = form['Keunggulan / Diferensiasi'] || '';
const hours = form['Jam Operasional'] || '';
const style = form['Gaya Bahasa'] || 'friendly-formal';
const location = form['Lokasi / Alamat'] || '';
const team = form['Profil Tim / Pengajar / Tenaga Ahli'] || '';
const curriculum = form['Kurikulum / Metode Kerja / Tahapan Layanan'] || '';
const refund = form['Kebijakan Refund / Pengembalian'] || '';
const guarantee = form['Kebijakan Garansi / Jaminan'] || '';
const testimonials = form['Testimoni / Social Proof'] || '';
const promo = form['Promo / Penawaran Terbatas'] || '';
const registration = form['Cara Daftar / Link Booking'] || '';
const extraFaq = form['FAQ Tambahan (Pertanyaan Spesifik)'] || '';
const commonIssues = form['Masalah Umum + Solusi'] || '';
const csRules = form['Aturan Khusus CS (Do/Don\'t)'] || '';

const profileBlock = `=== PROFIL BISNIS ===
Nama: ${bizName}
Jenis: ${bizType}
Deskripsi: ${description}
Produk/Paket + Harga:
${pricing}
Keunggulan: ${advantages}
Jam Operasional: ${hours}
Lokasi: ${location || '(tidak diisi)'}
Tim/Pengajar: ${team || '(tidak diisi)'}
Kurikulum/Metode: ${curriculum || '(tidak diisi)'}
Kebijakan Refund: ${refund || '(tidak diisi)'}
Garansi: ${guarantee || '(tidak diisi)'}
Testimoni: ${testimonials || '(tidak diisi)'}
Promo: ${promo || '(tidak diisi)'}
Cara Daftar: ${registration || '(tidak diisi)'}
FAQ Tambahan: ${extraFaq || '(tidak diisi)'}
Masalah Umum: ${commonIssues || '(tidak diisi)'}
Aturan CS: ${csRules || '(tidak diisi)'}
Gaya Bahasa: ${style}`;

const systemPrompt = `Kamu adalah AI Content Writer profesional yang membuat dokumen Knowledge Base untuk sistem Customer Service AI (chatbot RAG).

TUGAS: Buat dokumen "${item.title}" (tipe: ${item.kb_type}) berdasarkan profil bisnis di bawah.

${profileBlock}

=== INSTRUKSI DOKUMEN ===
${item.instruction}

=== ATURAN PENULISAN ===
1. Tulis HANYA berdasarkan informasi yang diberikan. JANGAN mengarang data.
2. Jika ada field "(tidak diisi)", buat konten yang wajar dan standar untuk jenis bisnis "${bizType}", tapi TANDAI dengan [PERLU REVIEW] agar human tahu bagian ini perlu diedit.
3. Gunakan gaya bahasa: ${style}.
4. Tulis dalam Bahasa Indonesia.
5. LANGSUNG tulis dokumen tanpa pembuka/penutup/komentar.
6. Format yang rapi dengan heading, sub-heading, dan bullet points.
7. Dokumen harus LENGKAP dan SIAP PAKAI sebagai sumber data AI chatbot.
8. Sebutkan nama bisnis "${bizName}" secara natural di dalam dokumen.`;

return [{
  json: {
    kb_type: item.kb_type,
    title: item.title,
    filename: item.filename,
    systemPrompt,
    userPrompt: `Tulis dokumen "${item.title}" yang lengkap untuk ${bizName}. LANGSUNG tulis konten dokumen.`
  }
}];

const raw = $input.first().json.text || $input.first().json.response?.text || $input.first().json.output || '';
const meta = $('Build Doc Prompt').first().json;

let content = raw.trim();

// Clean any XML/thinking tags that LLM might include
content = content
  .replace(/<thinking[\s\S]*?<\/thinking>/gi, '')
  .replace(/<analysis[\s\S]*?<\/analysis>/gi, '')
  .replace(/<reasoning[\s\S]*?<\/reasoning>/gi, '')
  .replace(/```/g, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

if (!content || content.length < 50) {
  content = `[ERROR] Gagal generate dokumen ${meta.title}. Silakan coba lagi.`;
}

// Add header to document
const header = `# ${meta.title}\n# Tipe KB: ${meta.kb_type}\n# Generated by RAG Document Generator\n# Tanggal: ${new Date().toISOString().slice(0,10)}\n# ⚠️ REVIEW dokumen ini sebelum upload ke KB Dashboard\n\n---\n\n`;

const finalContent = header + content;

return [{
  json: {
    kb_type: meta.kb_type,
    title: meta.title,
    filename: meta.filename,
    content: finalContent,
    charCount: finalContent.length,
    wordCount: finalContent.split(/\s+/).length
  }
}];

const items = $input.all();
const form = $('Input Profil Bisnis').first().json;
const bizName = form['Nama Bisnis'] || 'Unknown';

let totalChars = 0;
let totalWords = 0;
const summary = [];
const binaryOutputs = {};

for (let i = 0; i < items.length; i++) {
  const doc = items[i].json;
  totalChars += doc.charCount || 0;
  totalWords += doc.wordCount || 0;
  summary.push(`✅ ${doc.filename} — ${doc.wordCount} kata`);

  // Create binary file for download
  binaryOutputs[`file_${i}`] = {
    data: Buffer.from(doc.content, 'utf-8').toString('base64'),
    mimeType: 'text/plain',
    fileName: doc.filename
  };
}

return [{
  json: {
    bizName,
    totalDocs: items.length,
    totalChars,
    totalWords,
    summary: summary.join('\n'),
    generated_at: new Date().toISOString()
  },
  binary: binaryOutputs
}];
